#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    vector<long long> sorted = nums;
    sort(sorted.begin(), sorted.end());
    if (nums == sorted) {
        return 0;
    }

    long long k = 0;
    for (int bit = 30; bit >= 0; --bit) {
        long long candidate = k | (1LL << bit);
        bool possible = true;
        for (int i = 0; i < n; ++i) {
            if ((nums[i] & candidate) != candidate && nums[i] != sorted[i]) {
                possible = false;
                break;
            }
        }
        if (possible) {
            k = candidate;
        }
    }
    return k;
}
