#include <vector>
#include <algorithm>

using namespace std;

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    long long k = 0;
    for (int i = 0; i < n; ++i) {
        if (nums[i] == i) continue;
        if ((nums[i] & i) > k) {
            k = nums[i] & i;
        }
    }

    // Check if the array is already sorted
    bool sorted = true;
    for (int i = 0; i < n; ++i) {
        if (nums[i] != i) {
            sorted = false;
            break;
        }
    }
    if (sorted) return 0;

    return k;
}
